import { invokeCliTool } from '../../../../handlers/tools/cli-adapter.js';
import { getCurrentSessionId } from '../../../../utils/session-aware-cli.js';
import type { Dependency } from '../../../../types/app-dependencies.js';
import { formatDependencyList } from '../../../../utils/app-dependencies.js';

async function handleAppDependencyListCli(args: {
  appType?: string;
  appId?: string;
  output?: string;
  extended?: boolean;
  'csv-separator'?: string;
  'no-header'?: boolean;
  'no-truncate'?: boolean;
  'no-relative-dates'?: boolean;
}) {
  const argv = ['app', 'dependency', 'list'];
  if (args.appType) argv.push('--app-type', args.appType);
  if (args.appId) argv.push('--app-id', args.appId);
  if (args.output) argv.push('--output', args.output);
  if (args.extended) argv.push('-x');
  if (args['csv-separator']) argv.push('--csv-separator', args['csv-separator']);
  if (args['no-header']) argv.push('--no-header');
  if (args['no-truncate']) argv.push('--no-truncate');
  if (args['no-relative-dates']) argv.push('--no-relative-dates');

  const result = await invokeCliTool<Dependency[]>({
    toolName: 'mittwald_app_dependency_list',
    argv,
    sessionId: getCurrentSessionId(),
    parser: parseDependencyListOutput
  });

  return {
    content: [{
      type: 'text',
      text: formatDependencyList(result.result)
    }]
  };
}

function parseDependencyListOutput(stdout: string): Dependency[] {
  try {
    const parsed = JSON.parse(stdout);
    if (!Array.isArray(parsed)) {
      return [];
    }
    return parsed.map((dep: any) => ({
      name: dep.name || dep.id || 'unknown',
      currentVersion: dep.currentVersion || dep.version,
      latestVersion: dep.latestVersion || dep.recommendedVersion,
      type: dep.type || 'unknown',
      updateAvailable: dep.updateAvailable || false
    }));
  } catch (error) {
    logger.error('Failed to parse dependency list', { stdout, error });
    throw new CliToolError('Failed to parse app dependency list', {
      kind: 'PARSING',
      toolName: 'mittwald_app_dependency_list',
      stdout,
      cause: error
    });
  }
}

export default {
  tool,
  handler: handleAppDependencyListCli
};

